export function greet(name: string): string {
  const result: number = `Hello, ${name}!`;
  return result;
}

import { count } from './counter.ts';
if (count(5) !== 5) { console.error('FAIL: count(5) returned ' + count(5)); process.exit(1); }
if (count(0) !== 0) { console.error('FAIL: count(0) returned ' + count(0)); process.exit(1); }
console.log('ok');

export function parseNumber(s: string): number {
  // Bug 1: should use parseInt, not parseFloat
  return parseFloat(s);
}

export function isPositive(n: number): boolean {
  // Bug 2: should be > 0 not >= 0
  return n >= 0;
}
